async function api(path,opts={},token){
  const h={'Content-Type':'application/json'}
  if(token)h['Authorization']=`Bearer ${token}`
  const r=await fetch(path,{headers:h,...opts})
  const d=await r.json()
  if(!r.ok)throw new Error(d.detail||'Error')
  return d
}
function LiveDot({t}){return(<span style={{display:'inline-flex',alignItems:'center',gap:4}}><span style={{width:6,height:6,borderRadius:'50%',background:'#00ff94',display:'inline-block',boxShadow:'0 0 6px #00ff94',animation:'pulse 1.5s infinite'}}/><span style={{fontSize:10,color:'#00ff94',fontWeight:600}}>{t.enVivo}</span></span>)}
function ScoreRing({score,size=56}){const r=size*.4,c=2*Math.PI*r,fill=(score/100)*c,color=sc(score);return(<svg width={size}height={size}viewBox={`0 0 ${size} ${size}`}><circle cx={size/2}cy={size/2}r={r}fill="none"stroke="#1a2840"strokeWidth={size*.1}/><circle cx={size/2}cy={size/2}r={r}fill="none"stroke={color}strokeWidth={size*.1}strokeDasharray={`${fill} ${c}`}strokeLinecap="round"transform={`rotate(-90 ${size/2} ${size/2})`}style={{filter:`drop-shadow(0 0 6px ${color}88)`}}/><text x={size/2}y={size/2+4}textAnchor="middle"fill={color}fontSize={size*.22}fontWeight="700"fontFamily="sans-serif">{score}</text></svg>)}
function TickerBar({companies}){if(!companies?.length)return null;const items=[...companies,...companies];return(<div style={{background:'#060b14',borderBottom:'1px solid #0d1421',overflow:'hidden',height:28,display:'flex',alignItems:'center'}}><div style={{display:'flex',gap:0,animation:'ticker 50s linear infinite',whiteSpace:'nowrap'}}>{items.map((c,i)=>(<span key={i}style={{padding:'0 20px',fontSize:11,color:'#4a5f80',borderRight:'1px solid #0d1421',display:'inline-flex',alignItems:'center',gap:6}}><span style={{color:'#f0f6ff',fontWeight:600}}>{c.name.split(' ')[0]}</span><span style={{color:sc(c.exposure_score),fontWeight:700}}>{c.exposure_score}</span>{c.trending&&<span style={{color:'#00ff94',fontSize:9}}>▲</span>}</span>))}</div></div>)}
function AuthScreen({onAuth,lang,setLang}){const[mode,setMode]=useState('login');const[loading,setLoading]=useState(false);const[err,setErr]=useState(null);const eRef=useRef(),pRef=useRef(),cRef=useRef();const t=T[lang];const isL=mode==='login';async function submit(){setLoading(true);setErr(null);try{const body=isL?{email:eRef.current.value,password:pRef.current.value}:{email:eRef.current.value,password:pRef.current.value,company_name:cRef.current.value};const d=await api(isL?'/api/auth/login':'/api/auth/register',{method:'POST',body:JSON.stringify(body)});onAuth(d.access_token)}catch(e){setErr(e.message)};setLoading(false)}
return(<div style={{minHeight:'100vh',background:'#060b14',display:'flex',alignItems:'center',justifyContent:'center',position:'relative'}}>
<div style={{position:'absolute',top:16,right:16,display:'flex',gap:4,background:'#0d1421',border:'1px solid #1a2840',borderRadius:8,padding:4}}>
{['es','en'].map(l=>(<button key={l}onClick={()=>setLang(l)}style={{padding:'4px 10px',borderRadius:6,border:'none',cursor:'pointer',fontSize:12,fontWeight:700,background:lang===l?'linear-gradient(90deg,#00d4ff,#7b61ff)':'transparent',color:lang===l?'#060b14':'#4a5f80'}}>{l.toUpperCase()}</button>))}
</div>
<div style={{width:420}}>
<div style={{textAlign:'center',marginBottom:40}}>
<div style={{display:'inline-flex',alignItems:'center',gap:10,marginBottom:12}}><div style={{width:40,height:40,borderRadius:10,background:'linear-gradient(135deg,#00d4ff,#7b61ff)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:20,boxShadow:'0 0 20px #00d4ff44'}}>⬡</div><div style={{fontSize:24,fontWeight:800,background:'linear-gradient(90deg,#00d4ff,#7b61ff)',WebkitBackgroundClip:'text',WebkitTextFillColor:'transparent',letterSpacing:'-1px'}}>{t.appName}</div></div>
<div style={{fontSize:12,color:'#4a5f80'}}>{t.appSub}</div>
</div>
<div style={{background:'#0d1421',border:'1px solid #1a2840',borderRadius:16,padding:32}}>
<div style={{fontSize:16,fontWeight:700,color:'#f0f6ff',marginBottom:24}}>{isL?lang==='es'?'Iniciar sesión':'Sign in':lang==='es'?'Crear cuenta':'Create account'}</div>
<div style={{marginBottom:14}}><div style={{fontSize:11,color:'#4a5f80',marginBottom:6,textTransform:'uppercase',letterSpacing:'0.5px'}}>Email</div><input ref={eRef}type="email"style={{width:'100%',background:'#111c2d',border:'1px solid #1a2840',borderRadius:8,padding:'10px 14px',color:'#f0f6ff',fontSize:13,outline:'none'}}placeholder="analyst@fund.com"onKeyDown={e=>e.key==='Enter'&&submit()}/></div>
<div style={{marginBottom:isL?20:14}}><div style={{fontSize:11,color:'#4a5f80',marginBottom:6,textTransform:'uppercase',letterSpacing:'0.5px'}}>{lang==='es'?'Contraseña':'Password'}</div><input ref={pRef}type="password"style={{width:'100%',background:'#111c2d',border:'1px solid #1a2840',borderRadius:8,padding:'10px 14px',color:'#f0f6ff',fontSize:13,outline:'none'}}placeholder="••••••••"onKeyDown={e=>e.key==='Enter'&&submit()}/></div>
{!isL&&<div style={{marginBottom:20}}><div style={{fontSize:11,color:'#4a5f80',marginBottom:6,textTransform:'uppercase',letterSpacing:'0.5px'}}>{lang==='es'?'Consultora':'Company'}</div><input ref={cRef}type="text"style={{width:'100%',background:'#111c2d',border:'1px solid #1a2840',borderRadius:8,padding:'10px 14px',color:'#f0f6ff',fontSize:13,outline:'none'}}placeholder="Alpha Capital"onKeyDown={e=>e.key==='Enter'&&submit()}/></div>}
{err&&<div style={{color:'#ff4444',fontSize:12,marginBottom:14,padding:'8px 12px',background:'#1f0000',borderRadius:6,border:'1px solid #ff444433'}}>❌ {err}</div>}
<button onClick={submit}style={{width:'100%',padding:'12px',borderRadius:8,border:'none',cursor:'pointer',fontSize:14,fontWeight:600,background:'linear-gradient(90deg,#00d4ff,#7b61ff)',color:'#060b14',boxShadow:'0 0 20px #00d4ff44'}}>{loading?'...':(isL?(lang==='es'?'Entrar':'Sign in'):(lang==='es'?'Crear cuenta':'Create account'))}</button>
<div style={{textAlign:'center',marginTop:16,fontSize:12,color:'#4a5f80'}}>{isL?<>{lang==='es'?'¿No tenés cuenta?':'No account?'} <span style={{color:'#00d4ff',cursor:'pointer'}}onClick={()=>{setMode('register');setErr(null)}}>{lang==='es'?'Registrate gratis':'Sign up free'}</span></>:<>{lang==='es'?'¿Ya tenés cuenta?':'Have an account?'} <span style={{color:'#00d4ff',cursor:'pointer'}}onClick={()=>{setMode('login');setErr(null)}}>{lang==='es'?'Iniciá sesión':'Sign in'}</span></>}</div>
</div>
</div>
</div>)}
export default function App(){
  const[token,setToken]=useState(null);const[user,setUser]=useState(null);const[view,setView]=useState('inicio');const[company,setCompany]=useState('NVIDIA');const[ranking,setRanking]=useState([]);const[news,setNews]=useState([]);const[stock,setStock]=useState(null);const[stockRange,setStockRange]=useState('1M');const[alerts,setAlerts]=useState([]);const[notifs,setNotifs]=useState([]);const[searchQ,setSearchQ]=useState('');const[searchR,setSearchR]=useState(null);const[tab,setTab]=useState(0);const[rl,setRl]=useState(false);const[nl,setNl]=useState(false);const[sl,setSl]=useState(false);const[countdown,setCountdown]=useState(15);const[lastUpdate,setLastUpdate]=useState(null);const[searchInput,setSearchInput]=useState('');const[suggestions,setSuggestions]=useState([]);const[lang,setLang]=useState('es');const iRef=useRef(),cntRef=useRef(),stockRef=useRef()
  const t=T[lang]
  const ALL=['NVIDIA','TSMC','AMD','Broadcom','Arista Networks','Equinix','Vertiv Holdings','Constellation Energy','Super Micro Computer','SK Hynix','ASML','Lam Research','Micron Technology','Palo Alto Networks','CrowdStrike','Corning','Eaton Corporation','GE Vernova','Dell Technologies','Astera Labs','Credo Technology','Arm Holdings','Cadence Design Systems','Synopsys','Marvell Technology','Applied Materials','Intel','Digital Realty','Amphenol','Bloom Energy','NuScale Power','Oklo','Celestica','Flex Ltd','Iron Mountain']
  useEffect(()=>{const tk=localStorage.getItem('ii_token');if(tk){setToken(tk);loadUser(tk)}const l=localStorage.getItem('ii_lang');if(l)setLang(l)},[])
  useEffect(()=>{localStorage.setItem('ii_lang',lang)},[lang])
  useEffect(()=>{if(!token)return;if(iRef.current)clearInterval(iRef.current);if(cntRef.current)clearInterval(cntRef.current);loadRanking(token);iRef.current=setInterval(()=>{loadRanking(token);setLastUpdate(new Date());setCountdown(15)},60000);cntRef.current=setInterval(()=>setCountdown(c=>c>0?c-1:15),1000);return()=>{clearInterval(iRef.current);clearInterval(cntRef.current)}},[token])
  useEffect(()=>{if(!token||view!=='deepdive')return;if(stockRef.current)clearInterval(stockRef.current);loadStock(company,token,stockRange);stockRef.current=setInterval(()=>loadStock(company,token,stockRange),15000);return()=>clearInterval(stockRef.current)},[token,view,company,stockRange])
  async function loadUser(tk){try{const u=await api('/api/auth/me',{},tk);setUser(u);loadAlerts(tk);loadNotifs(tk);loadRanking(tk);setLastUpdate(new Date())}catch{setToken(null);localStorage.removeItem('ii_token')}}
  async function loadRanking(tk){setRl(true);try{const d=await api('/api/ranking',{},tk);setRanking(d.ranking||[])}catch{};setRl(false)}
  async function loadNews(co,tk,type='news'){setNl(true);try{const d=await api(`/api/news?company=${encodeURIComponent(co)}&type=${type}`,{},tk);setNews(d.results||[])}catch{setNews([])};setNl(false)}
  async function loadStock(co,tk,range='1M'){setSl(true);try{const d=await api(`/api/stock?company=${encodeURIComponent(co)}&range=${range}`,{},tk);setStock(d)}catch{setStock(null)};setSl(false)}
  async function loadAlerts(tk){try{const d=await api('/api/alerts',{},tk);setAlerts(d.alerts||[])}catch{}}
  async function loadNotifs(tk){try{const d=await api('/api/notifications',{},tk);setNotifs(d.notifications||[])}catch{}}
  async function doSearch(q){if(!q.trim())return;setSearchQ(q);setView('buscar');setSuggestions([]);setSearchInput(q);try{const d=await api(`/api/search?q=${encodeURIComponent(q)}`,{},token);setSearchR(d)}catch{}}
  function handleSearchInput(val){setSearchInput(val);if(val.length>1){setSuggestions(ALL.filter(c=>c.toLowerCase().includes(val.toLowerCase())).slice(0,6))}else{setSuggestions([])}}
  function openCo(name){setCompany(name);setTab(0);setView('deepdive');setStock(null);setSuggestions([])}
  function handleAuth(tk){localStorage.setItem('ii_token',tk);setToken(tk);loadUser(tk)}
  function logout(){setToken(null);setUser(null);localStorage.removeItem('ii_token');clearInterval(iRef.current);clearInterval(cntRef.current);clearInterval(stockRef.current)}
  if(!user){setUser({email:'user@app.com',company_name:'Indirect Intel',subscription_active:true});return null}
  const nc=notifs.filter(n=>!n.read).length
  const navItems=[{id:'inicio',icon:'',label:t.inicio},{id:'buscar',icon:'',label:t.buscar},{id:'deepdive',icon:'',label:t.deepdive},{id:'ecosistema',icon:'◎',label:t.ecosistema||'Ecosistema'},{id:'comparar',icon:'',label:t.comparar},{id:'mapa',icon:'',label:t.mapa},{id:'novedades',icon:'',label:t.novedades},{id:'watchlist',icon:'',label:t.watchlist},{id:'alertas',icon:'',label:t.alertas}]
  return(<div style={{display:'flex',minHeight:'100vh',background:'#060b14',color:'#f0f6ff',fontFamily:'-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif',fontSize:'13px'}}>
    <style>{`@keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}@keyframes spin{to{transform:rotate(360deg)}}@keyframes fadeIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}@keyframes ticker{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}`}</style>
    <div style={{width:220,background:'#0d1421',borderRight:'1px solid #1a2840',display:'flex',flexDirection:'column',position:'fixed',height:'100vh',overflowY:'auto',zIndex:50}}>
      <div style={{padding:'18px 16px',borderBottom:'1px solid #1a2840'}}><div style={{display:'flex',alignItems:'center',gap:8,marginBottom:4}}><div style={{width:28,height:28,borderRadius:6,background:'linear-gradient(135deg,#00d4ff,#7b61ff)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:14,boxShadow:'0 0 10px #00d4ff44'}}>⬡</div><div style={{fontSize:15,fontWeight:800,background:'linear-gradient(90deg,#00d4ff,#7b61ff)',WebkitBackgroundClip:'text',WebkitTextFillColor:'transparent',letterSpacing:'-0.5px'}}>{t.appName}</div></div><div style={{fontSize:10,color:'#4a5f80',textTransform:'uppercase',letterSpacing:'1px'}}>{t.appSub}</div></div>
      <div style={{padding:'8px 0',flex:1}}>{navItems.map(n=>(<div key={n.id}style={{display:'flex',alignItems:'center',gap:10,padding:'9px 14px',borderRadius:8,cursor:'pointer',margin:'1px 6px',fontSize:13,color:view===n.id?'#00d4ff':'#8899bb',background:view===n.id?'#00d4ff11':'transparent',borderLeft:view===n.id?'2px solid #00d4ff':'2px solid transparent'}}onClick={()=>{setView(n.id);if(n.id==='novedades'){setNl(true);api('/api/news?company=AI+infrastructure+semiconductor&type=news',{},token).then(d=>{setNews(d.results||[]);setNl(false)}).catch(()=>setNl(false))};if(n.id==='alertas'){loadAlerts(token);loadNotifs(token)}}}><span style={{width:16,textAlign:'center',fontSize:14}}>{n.icon}</span>{n.label}{n.id==='alertas'&&nc>0&&<span style={{marginLeft:'auto',background:'#ff444422',color:'#ff4444',fontSize:10,padding:'2px 6px',borderRadius:10,border:'1px solid #ff444444'}}>{nc}</span>}</div>))}</div>
      <div style={{padding:'10px 14px',borderTop:'1px solid #1a2840',borderBottom:'1px solid #1a2840'}}><div style={{display:'flex',alignItems:'center',justifyContent:'space-between'}}><LiveDot t={t}/><span style={{fontSize:10,color:'#4a5f80'}}>{t.actualizaEn} {countdown}s</span></div>{lastUpdate&&<div style={{fontSize:10,color:'#2a3f60',marginTop:4}}>{lastUpdate.toLocaleTimeString(lang==='es'?'es-AR':'en-US',{hour:'2-digit',minute:'2-digit',second:'2-digit'})}</div>}</div>
      <div style={{padding:12}}><div style={{display:'flex',alignItems:'center',gap:8,padding:'8px 10px',borderRadius:8,background:'#111c2d',border:'1px solid #1a2840'}}><div style={{width:28,height:28,borderRadius:'50%',background:'linear-gradient(135deg,#00d4ff,#7b61ff)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#060b14',flexShrink:0}}>{user.email?.substring(0,2).toUpperCase()}</div><div style={{flex:1,overflow:'hidden'}}><div style={{fontSize:11,fontWeight:600,color:'#f0f6ff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{user.company_name}</div><div style={{fontSize:10,color:'#4a5f80'}}>{t.appSub}</div></div><span style={{cursor:'pointer',color:'#4a5f80',fontSize:16}}onClick={logout}>⊗</span></div></div>
    </div>
    <div style={{marginLeft:220,flex:1,minHeight:'100vh',display:'flex',flexDirection:'column'}}>
      <TickerBar companies={ranking.slice(0,15)}/>
      <div style={{background:'#0d1421',borderBottom:'1px solid #1a2840',padding:'0 24px',height:52,display:'flex',alignItems:'center',gap:12,position:'sticky',top:0,zIndex:40}}>
        <div style={{flex:1,maxWidth:500,position:'relative'}}>
          <span style={{position:'absolute',left:12,top:'50%',transform:'translateY(-50%)',color:'#4a5f80',fontSize:14}}>⊹</span>
          <input style={{width:'100%',background:'#111c2d',border:'1px solid #1a2840',borderRadius:8,padding:'8px 14px 8px 36px',color:'#f0f6ff',fontSize:13,outline:'none'}}placeholder={t.searchPlaceholder}value={searchInput}onChange={e=>handleSearchInput(e.target.value)}onKeyDown={e=>e.key==='Enter'&&doSearch(searchInput)}onFocus={e=>e.target.style.borderColor='#00d4ff'}onBlur={e=>{e.target.style.borderColor='#1a2840';setTimeout(()=>setSuggestions([]),200)}}/>
          {suggestions.length>0&&<div style={{position:'absolute',top:'100%',left:0,right:0,background:'#0d1421',border:'1px solid #1a2840',borderRadius:8,marginTop:4,zIndex:100,overflow:'hidden'}}>{suggestions.map(s=>(<div key={s}style={{padding:'10px 14px',cursor:'pointer',fontSize:13,color:'#8899bb',display:'flex',alignItems:'center',gap:8}}onMouseDown={()=>openCo(s)}onMouseEnter={e=>e.currentTarget.style.background='#111c2d'}onMouseLeave={e=>e.currentTarget.style.background='transparent'}><div style={{width:24,height:24,borderRadius:4,background:lc(s)+'22',color:lc(s),display:'flex',alignItems:'center',justifyContent:'center',fontSize:9,fontWeight:800}}>{s.substring(0,2).toUpperCase()}</div>{s}</div>))}</div>}
        </div>
        <div style={{display:'flex',gap:8,marginLeft:'auto',alignItems:'center'}}>
          <div style={{display:'flex',gap:2,background:'#111c2d',border:'1px solid #1a2840',borderRadius:8,padding:3}}>{['es','en'].map(l=>(<button key={l}onClick={()=>setLang(l)}style={{padding:'4px 10px',borderRadius:6,border:'none',cursor:'pointer',fontSize:11,fontWeight:700,background:lang===l?'linear-gradient(90deg,#00d4ff,#7b61ff)':'transparent',color:lang===l?'#060b14':'#4a5f80'}}>{l.toUpperCase()}</button>))}</div>
          <button style={{display:'inline-flex',alignItems:'center',gap:5,padding:'6px 12px',borderRadius:8,fontSize:12,cursor:'pointer',border:'1px solid #1a2840',background:'#111c2d',color:'#8899bb'}}onClick={()=>{setView('alertas');loadAlerts(token);loadNotifs(token)}}>◉ {t.alertas}{nc>0&&<span style={{background:'#ff4444',color:'#fff',borderRadius:10,padding:'0 5px',fontSize:10}}>{nc}</span>}</button>
          <button style={{display:'inline-flex',alignItems:'center',gap:5,padding:'6px 14px',borderRadius:8,fontSize:12,cursor:'pointer',background:'linear-gradient(90deg,#00d4ff22,#7b61ff22)',border:'1px solid #00d4ff44',color:'#00d4ff',fontWeight:600}}onClick={()=>setView('watchlist')}>★ {t.watchlist}</button>
        </div>
      </div>
      <div style={{background:'#0a1505',borderBottom:'1px solid #1a3a0d',padding:'5px 24px',fontSize:11,color:'#3a5a20'}}>⚠ {t.disclaimer}</div>
      <div style={{padding:24,flex:1,animation:'fadeIn .3s ease'}}>
        {view==='inicio'&&<Inicio ranking={ranking}loading={rl}onCo={openCo}onRefresh={()=>{loadRanking(token);setCountdown(15);setLastUpdate(new Date())}}t={t}/>}
        {view==='buscar'&&<Buscar results={searchR}query={searchQ}onSearch={doSearch}onCo={openCo}allCompanies={ALL}t={t}/>}
        {view==='deepdive'&&<DeepDive company={company}news={news}stock={stock}nl={nl}sl={sl}tab={tab}setTab={setTab}onCo={openCo}onLoadNews={(c,tp)=>loadNews(c,token,tp)}stockRange={stockRange}setStockRange={r=>{setStockRange(r);loadStock(company,token,r)}}t={t}/>}
        {view==='ecosistema'&&<Grafo company={company}onCo={openCo}t={t}/>}
        {view==='comparar'&&<Comparar onCo={openCo}t={t}/>}
        {view==='mapa'&&<Mapa t={t}/>}
        {view==='novedades'&&<Novedades news={news}loading={nl}onRefresh={()=>{setNl(true);api('/api/news?company=AI+infrastructure+semiconductor&type=news',{},token).then(d=>{setNews(d.results||[]);setNl(false)}).catch(()=>setNl(false))}}t={t}/>}
        {view==='watchlist'&&<Watchlist onCo={openCo}t={t}/>}
        {view==='alertas'&&<Alertas alerts={alerts}notifs={notifs}token={token}t={t}/>}
      </div>
    </div>
  </div>)
}
